let currentFilter = 'todos';
let bibleFilter = 'hoy';
let promiseView = 'todas';
function get(k,f){try{return JSON.parse(localStorage.getItem(k)) ?? f}catch(e){return f}}
function set(k,v){localStorage.setItem(k,JSON.stringify(v))}
function el(id){return document.getElementById(id)}
function show(id){document.querySelectorAll('.tab').forEach(t=>t.classList.remove('active')); const target=el(id); if(target) target.classList.add('active'); if(id==='devocional')renderDevos(); if(id==='juegos')renderGames(); if(id==='calendario')renderCalendar(); if(id==='promesas')renderPromises(); if(id==='anio')renderBibleYear(); if(id==='progreso')renderProgress(); window.scrollTo({top:0,behavior:'smooth'})}
function renderDevos(){let done=get('doneDevos',[]); const box=el('devoBox'); if(!box)return; box.innerHTML=devos.map((d,i)=>`<div class="card ${done.includes(i)?'done':''}"><span class="badge">Día ${d.day}</span><h3>${d.title}</h3><p class="verse"><b>${d.verse}</b></p><p class="devoSectionTitle">🌷 Reflexión</p><p>${d.reflection}</p><p class="devoSectionTitle">🙏 Oración</p><p>${d.prayer}</p><div class="devoQuestion"><b>✍️ Para escribir en tu diario:</b><br>${d.question}</div><div class="devoPromise">💜 Promesa: ${d.promise}</div><button class="primary" onclick="toggleDevo(${i})">${done.includes(i)?'Completado ✓':'Marcar completado'}</button></div>`).join('')}
function toggleDevo(i){let a=get('doneDevos',[]); a=a.includes(i)?a.filter(x=>x!==i):[...a,i]; set('doneDevos',a); renderDevos(); renderCalendar(); renderProgress()}
function filterGames(f){currentFilter=f; renderGames()}
function renderGames(){let done=get('doneGames',[]); let list=games.map((g,i)=>({...g,idx:i})); if(currentFilter==='pendientes')list=list.filter(g=>!done.includes(g.idx)); if(currentFilter==='completados')list=list.filter(g=>done.includes(g.idx)); const box=el('gamesBox'); if(!box)return; box.innerHTML=list.map(g=>`<div class="card ${done.includes(g.idx)?'done':''}"><span class="badge">Día ${g.day}</span><div class="gameType">${g.type}</div><h3>🏆 ${g.title}</h3><p>${g.prompt}</p><textarea id="gameResponse${g.idx}" placeholder="Escribe tu respuesta o reflexión...">${get('gameResponses',{})[g.idx]||''}</textarea><button class="secondary" onclick="saveGameResponse(${g.idx})">Guardar respuesta</button><button class="secondary" onclick="showAnswer(${g.idx})">Ver ayuda / respuesta</button><div class="answerBox" id="answer${g.idx}"><b>Respuesta:</b> ${g.answer}<br><span class="rewardTag">${g.reward}</span></div><button class="primary" onclick="toggleGame(${g.idx})">${done.includes(g.idx)?'Completado ✓':'Completar y ganar flor'}</button></div>`).join('')||'<div class="card">No hay juegos en este filtro.</div>'; renderGarden()}
function showAnswer(i){const a=el('answer'+i); if(a)a.style.display='block'}
function saveGameResponse(i){let r=get('gameResponses',{}); let e=el('gameResponse'+i); if(e)r[i]=e.value; set('gameResponses',r); alert('Respuesta guardada 💜')}
function toggleGame(i){let a=get('doneGames',[]); a=a.includes(i)?a.filter(x=>x!==i):[...a,i]; set('doneGames',a); renderGames(); renderProgress()}
function renderGarden(){let done=get('doneGames',[]); const box=el('gardenBox'); if(box)box.innerHTML=done.length?done.map(i=>`<div class="flowerReward">${(games[i]?.reward||'🌸').split(' ')[0]}</div>`).join(''):'<p>Completa juegos para llenar tu jardín de flores 🌱</p>'; if(el('gameProgressText'))el('gameProgressText').textContent=`Juegos completados: ${done.length}/31`;}
function addPrayer(){let name=el('pName').value.trim(); let need=el('pNeed').value.trim(); if(!need){alert('Escribe tu petición 💜'); return} let a=get('prayers',[]); a.push({id:Date.now(),name:name||'Petición',need,done:false}); set('prayers',a); el('pName').value=''; el('pNeed').value=''; renderPrayers()}
function renderPrayers(){let a=get('prayers',[]); const box=el('prayerBox'); if(!box)return; box.innerHTML=a.map(p=>`<div class="card ${p.done?'done':''}"><h3>${p.name||'Petición'}</h3><p>${p.need}</p><button class="secondary" onclick="togglePrayer(${p.id})">${p.done?'Contestada ✓':'Marcar contestada'}</button></div>`).join('')||'<div class="card">Añade tu primera petición.</div>'}
function togglePrayer(id){let a=get('prayers',[]); let p=a.find(x=>x.id===id); if(p)p.done=!p.done; set('prayers',a); renderPrayers(); renderProgress()}
function todayUS(){const d=new Date(); return String(d.getMonth()+1).padStart(2,'0')+'/'+String(d.getDate()).padStart(2,'0')+'/'+d.getFullYear()}
function saveJournal(){let e=get('journal',[]); e.push({date:el('jDate').value||todayUS(),text:el('jText').value,thanks:el('jThanks').value}); set('journal',e); el('jText').value=''; el('jThanks').value=''; renderJournal()}
function renderJournal(){let e=get('journal',[]); const box=el('journalBox'); if(!box)return; box.innerHTML=e.slice().reverse().map(x=>`<div class="card"><h3>${x.date}</h3><p>${x.text}</p><p><b>Gratitud:</b> ${x.thanks}</p></div>`).join('')||'<div class="card">Todavía no has escrito en tu diario.</div>'}
function renderCalendar(){let done=get('doneDevos',[]); const box=el('calendarBox'); if(!box)return; box.innerHTML=''; for(let i=0;i<31;i++)box.innerHTML+=`<button class="day ${done.includes(i)?'doneDay':''}" onclick="toggleDevo(${i})">${i+1}<br>${done.includes(i)?'✓':''}</button>`; if(el('calendarSummary'))el('calendarSummary').textContent=`Devocionales completados: ${done.length}/31`;}
function setPromiseView(v){promiseView=v; renderPromises()}
function allPromises(){return promiseLibrary.concat(get('customPromises',[]))}
function renderDailyPromise(){const p=promiseLibrary[new Date().getDate()%promiseLibrary.length]; if(el('dailyPromiseText'))el('dailyPromiseText').textContent='“'+p.text+'”'; if(el('dailyPromiseRef'))el('dailyPromiseRef').textContent=p.ref}
function favoriteDailyPromise(){const p=promiseLibrary[new Date().getDate()%promiseLibrary.length]; let f=get('favPromises',[]); if(!f.some(x=>x.ref===p.ref))f.push(p); set('favPromises',f); renderPromises(); alert('Promesa guardada 💜')}
function renderPromises(){renderDailyPromise(); let list=allPromises(); const q=(el('promiseSearch')?.value||'').toLowerCase(); if(promiseView==='favoritas')list=get('favPromises',[]); if(promiseView==='mias')list=get('customPromises',[]); if(q)list=list.filter(p=>(p.ref+' '+p.text+' '+(p.cat||'')).toLowerCase().includes(q)); const box=el('promisesBox'); if(!box)return; box.innerHTML=list.map((p,i)=>`<div class="card promiseCard"><span class="categoryPill">${p.cat||'Promesa'}</span><h3>${p.ref}</h3><p>${p.text}</p><button class="secondary" onclick="copyText('${(p.ref+' - '+p.text).replace(/'/g,"\'")}')">📋 Copiar</button></div>`).join('')||'<div class="card">No hay promesas en esta sección.</div>'}
function copyText(t){if(navigator.clipboard)navigator.clipboard.writeText(t); alert('Copiado 💜')}
function addPromise(){let ref=el('newPromiseRef').value.trim(), text=el('newPromiseText').value.trim(); if(!ref||!text){alert('Escribe referencia y promesa'); return} let c=get('customPromises',[]); c.push({ref,text,cat:'Personal'}); set('customPromises',c); el('newPromiseRef').value=''; el('newPromiseText').value=''; promiseView='mias'; renderPromises()}
function filterBible(f){bibleFilter=f; renderBibleYear()}
function bibleDayOfYear(){const now=new Date(); const start=new Date(now.getFullYear(),0,0); return Math.floor((now-start)/86400000)}
function renderBibleYear(){let done=get('bibleDone',[]); let day=bibleDayOfYear(); let list=biblePlan.map((b,i)=>({...b,idx:i})); if(bibleFilter==='hoy')list=list.filter(b=>b.day===day); if(bibleFilter==='pendientes')list=list.filter(b=>!done.includes(b.idx)).slice(0,31); if(bibleFilter==='completados')list=list.filter(b=>done.includes(b.idx)); const box=el('bibleBox'); if(!box)return; box.innerHTML=list.map(b=>`<div class="card ${done.includes(b.idx)?'done':''}"><span class="badge">Día ${b.day}</span><h3>📖 ${b.reading}</h3><p>${b.focus}</p><button class="primary" onclick="toggleBible(${b.idx})">${done.includes(b.idx)?'Lectura completada ✓':'Marcar lectura completada'}</button></div>`).join('')||'<div class="card">No hay lecturas en este filtro.</div>'; const pct=Math.round(done.length/365*100); if(el('bibleCircle'))el('bibleCircle').textContent=pct+'%'; if(el('bibleSummary'))el('bibleSummary').textContent=`Lecturas completadas: ${done.length}/365`; renderProgress()}
function toggleBible(i){let a=get('bibleDone',[]); a=a.includes(i)?a.filter(x=>x!==i):[...a,i]; set('bibleDone',a); renderBibleYear();}
function renderProgress(){let d=get('doneDevos',[]).length,g=get('doneGames',[]).length,p=get('prayers',[]).filter(x=>x.done).length,b=get('bibleDone',[]).length; if(el('progressCircle'))el('progressCircle').textContent=Math.round(d/31*100)+'%'; if(el('progressText'))el('progressText').textContent=`Devocionales: ${d}/31 • Juegos: ${g}/31 • Año Bíblico: ${b}/365 • Oraciones contestadas: ${p}`; let badges=[]; if(d>=7)badges.push('📖 Mujer de la Palabra'); if(g>=10)badges.push('🏆 Guerrera Bíblica'); if(b>=7)badges.push('📚 Constante en la Biblia'); if(p>=1)badges.push('🙏 Intercesora'); if(d>=31)badges.push('💜 Mes Completado'); if(el('badgeBox'))el('badgeBox').innerHTML=badges.map(x=>`<span class="spiritualBadge">${x}</span>`).join(''); if(el('certificateStatus'))el('certificateStatus').textContent=d>=31?'Tu certificado está listo para imprimir 💜':`Completa los 31 devocionales para finalizar. Llevas ${d}/31.`}
function downloadBackup(){let data={doneDevos:get('doneDevos',[]),doneGames:get('doneGames',[]),bibleDone:get('bibleDone',[]),prayers:get('prayers',[]),journal:get('journal',[]),customPromises:get('customPromises',[])}; let blob=new Blob([JSON.stringify(data,null,2)],{type:'application/json'}); let a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download='respaldo-jardin-oracion.json'; a.click()}
function setupNetlifyForm(){const form=el('specialPrayerForm'); if(!form)return; form.addEventListener('submit',function(e){e.preventDefault(); const nombre=el('specialPrayerName').value.trim(); const peticion=el('specialPrayerText').value.trim(); const fecha=new Date().toLocaleString('es-US'); if(!nombre||!peticion){el('specialPrayerStatus').textContent='Por favor escribe el nombre y la petición.'; return} el('specialPrayerDate').value=fecha; let local=get('specialPrayers',[]); local.push({name:nombre,text:peticion,date:fecha}); set('specialPrayers',local); el('specialPrayerStatus').textContent='Enviando petición...'; fetch('https://formspree.io/f/xwvdwnqo',{method:'POST',headers:{'Content-Type':'application/x-www-form-urlencoded'},body:new URLSearchParams({'form-name':'peticiones-oracion','nombre':nombre,'peticion':peticion,'fecha':fecha}).toString()}).then(()=>{el('specialPrayerStatus').textContent='Petición enviada correctamente. Estaremos orando por ti. 💜'; form.reset();}).catch(()=>{el('specialPrayerStatus').textContent='Petición enviada correctamente. También quedó guardada en tu dispositivo.';})})}
document.addEventListener('DOMContentLoaded',function(){ if(el('jDate'))el('jDate').value=todayUS(); renderDevos(); renderGames(); renderPrayers(); renderJournal(); renderCalendar(); renderPromises(); renderBibleYear(); renderProgress(); setupNetlifyForm(); });
